import json, re
from preds_day1 import P
from preds_day1b import P2

# Corrections for entries I got wrong on first pass
CORR = {
 "350082": {"Richard Rosenberg": 0.10, "Michael Brown": 0.09, "David Goldberg": 0.08, "James Miller": 0.08, "Aaron Cohen": 0.07},  # Michigan synagogue assailant NAME (unknowable)
 "48811": {"Beth Israel Synagogue": 0.10, "Young Israel Synagogue": 0.09, "Chabad of Michigan": 0.09, "Shaarey Zedek": 0.08, "Temple Israel": 0.07},  # synagogue name
 "521564": {"Joel Sagar": 0.10, "Anju Kumar": 0.09, "Bello Muhammad": 0.08, "Raju Khan": 0.08, "Mohammed Idris": 0.07},
}

merged = {}
for src in (P, P2):
    for q, d in src.items():
        if q in CORR:
            continue
        merged[q] = dict(d)
for q, d in CORR.items():
    merged[q] = dict(d)

# Clean: drop zero/neg/empty, dedupe case-insensitive (keep max), drop obvious dupes
clean = {}
for q, d in merged.items():
    seen = {}
    for k, v in d.items():
        k = k.strip()
        if v is None: continue
        v = float(v)
        if v <= 0: continue
        key = k
        # collapse exact dupes -> sum
        if key in seen:
            seen[key] = seen[key] + v
        else:
            seen[key] = v
    # dedupe near-duplicate keys (same lower) keeping the larger value
    low = {}
    for k, v in seen.items():
        lk = k.lower()
        if lk in low:
            if v > low[lk][1]:
                low[lk] = (k, v)
        else:
            low[lk] = (k, v)
    final = {k: v for (k, v) in low.values()}
    s = sum(final.values())
    if s > 1.0 + 1e-9:
        # renormalize
        final = {k: v / s for k, v in final.items()}
        s = 1.0
    clean[q] = final

# Load all qids
import pandas as pd
df = pd.read_csv('market.csv', dtype={'qid': str})
allq = set(df['qid'].tolist())

missing = allq - set(clean.keys())
extra = set(clean.keys()) - allq
print("Total clean:", len(clean))
print("Missing (uncovered):", len(missing), sorted(missing)[:20])
print("Extra (not in market):", len(extra), sorted(extra)[:20])
print("All 330 covered:", len(missing)==0)

# report any sum issues
bad = [(q, round(sum(v.values()),4)) for q,v in clean.items() if sum(v.values())>1.0001 or sum(v.values())<0.3]
print("Sum issues:", bad[:20])

with open('/workspace/final_preds.json','w') as f:
    json.dump(clean, f, indent=0)
print("Wrote final_preds.json with", len(clean), "predictions")
